        position: absolute;
        top: 10px;
        right: 15px;
        font-size: 24px;
        cursor: pointer;
        color: #999;
        width: 24px;
        height: 24px;
        line-height: 24px;
        text-align: center;
        border-radius: 50%;
        transition: all 0.2s;
        z-index: 10001;
    }

    .modal-close:hover {
        background: #f0f0f0;
        color: #666;
    }

    .modal-qrcode {
        margin-bottom: 15px;
    }

    .modal-qrcode img {
        width: 200px;
        height: 200px;
        border-radius: 6px;
        object-fit: contain;
        background: #f8f8f8;
        padding: 10px;
        box-sizing: border-box;
    }

    .modal-title {
        font-size: 16px;
        font-weight: 600;
        color: #333;
        margin-bottom: 10px;
        padding: 0 10px;
        word-break: break-all;
    }

    .modal-hint {
        font-size: 12px;
        color: #888;
        margin-top: 15px;
        padding-top: 10px;
        border-top: 1px solid #eee;
    }

    /* 移动端优化 */
    @media (max-width: 480px) {
        .modal-content {
            padding: 20px;
            max-width: 280px;
        }

        .modal-qrcode img {
            width: 180px;
            height: 180px;
        }

        .modal-title {
            font-size: 14px;
        }
    }
