		.flex {
        display: flex;
        justify-content: space-between;
        align-items: center;
		padding:10px 0 10px 0;
    }

    .qrcode-wrap {
        flex: 1;
        padding-top: 20px;
        margin: 0 0px;
        flex-wrap: nowrap;
        overflow-x: auto;
		display:grid;
		grid-template-columns:repeat(8,1fr);
		width:100%;
    }

    .qrcode-wrap::-webkit-scrollbar {
        display: none; /* Chrome, Safari */
    }

    .qrcode-wrap .qrcode {
        background-color: #f5f5f5;
        text-align: center;
        display: flex;
        flex-direction: column;
        margin-left: 4px;
        padding: 4px 2px;
        align-items: center;
        flex-shrink: 0;
        cursor: pointer;
        transition: transform 0.2s ease;
        border-radius: 4px;
    }

    .qrcode-wrap .qrcode:hover {
        transform: translateY(-2px);
        box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    }

    .qrcode-wrap .qrcode img {
        width: 100%;
        margin-bottom: 3px;
    }

    .qrcode-wrap .qrcode .name {
        line-height: 1;
        overflow: hidden;
        white-space: nowrap;
        font-size: 9px;
        text-overflow: ellipsis;
    }

    /* 放大预览模态框样式 */
    .qrcode-modal {
        display: none;
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        z-index: 9999;
        align-items: center;
        justify-content: center;
        padding: 20px;
        box-sizing: border-box;
    }

    .modal-overlay {
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background: #99999985;
        backdrop-filter: blur(3px);
    }

    .modal-content {
        position: relative;
        z-index: 10000;
        background: white;
        border-radius: 12px;
        padding: 25px;
        max-width: 300px;
        width: 100%;
        text-align: center;
        box-shadow: 0 10px 40px rgba(0, 0, 0, 0.3);
        animation: modalSlideIn 0.3s ease-out;
    }

    @keyframes modalSlideIn {
        from {
            opacity: 0;
            transform: scale(0.9) translateY(20px);
        }
        to {
            opacity: 1;
            transform: scale(1) translateY(0);
        }
    }

    .modal-close {
        position: absolute;
        top: 10px;
        right: 15px;
        font-size: 24px;
        cursor: pointer;
        color: #999;
        width: 24px;
        height: 24px;
        line-height: 24px;
        text-align: center;
        border-radius: 50%;
        transition: all 0.2s;
        z-index: 10001;
    }

    .modal-close:hover {
        background: #f0f0f0;
        color: #666;
    }

    .modal-qrcode {
        margin-bottom: 15px;
    }

    .modal-qrcode img {
        width: 200px;
        height: 200px;
        border-radius: 6px;
        object-fit: contain;
        background: #f8f8f8;
        padding: 10px;
        box-sizing: border-box;
    }

    .modal-title {
        font-size: 16px;
        font-weight: 600;
        color: #333;
        margin-bottom: 10px;
        padding: 0 10px;
        word-break: break-all;
    }

    .modal-hint {
        font-size: 12px;
        color: #888;
        margin-top: 15px;
        padding-top: 10px;
        border-top: 1px solid #eee;
    }

    /* 移动端优化 */
    @media (max-width: 480px) {
        .modal-content {
            padding: 20px;
            max-width: 280px;
        }

        .modal-qrcode img {
            width: 180px;
            height: 180px;
        }

        .modal-title {
            font-size: 14px;
        }
    }
		</style>
