  {title:"乌方袭击俄多地能源设施 俄方空袭乌军工等设施", url:"https://mil.news.sina.com.cn/zonghe/2026-07-07/doc-inifxtrc8241332.shtml"},
  {title:"国际观察｜前线拉锯 纵深互袭——军事专家解读俄乌高烈度交锋", url:"https://mil.news.sina.com.cn/zonghe/2026-07-07/doc-inifxtrf1598133.shtml"},
  {title:"军事专家：中俄联演为地区和平稳定作出贡献", url:"https://mil.news.sina.com.cn/zonghe/2026-07-07/doc-inifxtrh8365727.shtml"},
  {title:"展翅十年 "鲲鹏"飞出强军航迹", url:"https://mil.news.sina.com.cn/zonghe/2026-07-07/doc-inifxtrf1588081.shtml"},
  {title:"霹雳惊寒夜 弹道映雪山", url:"https://mil.news.sina.com.cn/zonghe/2026-07-07/doc-inifxpik8407862.shtml"},
  {title:"广西多地持续遭遇强降雨引发洪涝灾害 解放军和武警部队官兵、民兵迅速投入抢险救灾", url:"https://mil.news.sina.com.cn/zonghe/2026-07-07/doc-inifxpii1619855.shtml"},
  {title:"乌克兰基辅遭空袭9人死亡", url:"https://mil.news.sina.com.cn/zonghe/2026-07-06/doc-inifvzfx8759650.shtml"},
  {title:"中国海军成功组织潜射战略导弹试射", url:"https://mil.news.sina.com.cn/zonghe/2026-07-06/doc-inifvzfz1867238.shtml"}
];

const results = [];

for (const art of articles) {
  try {
    const resp = await fetch(art.url);
    const html = await resp.text();
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');

    // 提取真实标题：优先 h1.main-title，其次 title 标签
    let realTitle = '';
    const h1 = doc.querySelector('h1.main-title') || doc.querySelector('h1');
    if (h1) {
      realTitle = h1.textContent.trim();
    }
    if (!realTitle) {
      const titleTag = doc.querySelector('title');
      if (titleTag) {
        realTitle = titleTag.textContent.trim().replace(/_.*$/, '').trim();
      }
    }
    if (!realTitle) realTitle = art.title;

    // 提取来源
    let source = '';
    const sourceEl = doc.querySelector('.source') || doc.querySelector('.article-source') || doc.querySelector('span[class*="source"]');
    if (sourceEl) source = sourceEl.textContent.trim();
    if (!source) {
      // 从 title 标签中提取来源
      const titleTag = doc.querySelector('title');
      if (titleTag) {
        const m = titleTag.textContent.match(/_(\w+新闻|新华社|人民日报|环球时报|央视|中新网|参考消息|观察者网)/);
        if (m) source = m[1];
      }
    }

    // 提取发布时间
    let pubDate = '';
    const dateEl = doc.querySelector('.date') || doc.querySelector('span[class*="date"]') || doc.querySelector('.pub_time');
    if (dateEl) pubDate = dateEl.textContent.trim();
    if (!pubDate) {
      const m = html.match(/<!-- publish date: ([\d-]+ [\d:]+)/);
      if (m) pubDate = m[1];
    }
    if (!pubDate) {
      const m2 = art.url.match(/(\d{4}-\d{2}-\d{2})/);
      if (m2) pubDate = m2[1];
    }

    // 提取正文
    let content = '';
    const articleDiv = doc.querySelector('#article') || doc.querySelector('.article-content') || doc.querySelector('div[class*="article"]');
    if (articleDiv) {
      const ps = articleDiv.querySelectorAll('p');
      const paragraphs = [];
      ps.forEach(p => {
        const t = p.textContent.trim();
        if (t && t.length > 2) paragraphs.push(t);
      });
      content = paragraphs.join('\n\n');
    }
    if (!content) content = '(正文提取失败)';

    results.push({
      title: realTitle,
      source: source || '新浪军事',
      date: pubDate,
      url: art.url,
      content: content.substring(0, 800)
    });
  } catch(e) {
    results.push({
      title: art.title,
      source: '新浪军事',
      date: '',
      url: art.url,
      content: '(抓取失败: ' + e.message + ')'
    });
  }
}

return results;
